def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace. 
    If no whitespaces exist in the text, split on commas ','. 
    If neither exists, return the count of lowercase letters in odd order in the alphabet 
    (e.g., ord('a') = 0, ord('b') = 1, ..., ord('z') = 25).

    Examples:
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") ➞ 3 
    '''

    # Check for whitespace and split accordingly
    if ' ' in txt:
        return txt.split()
    elif ',' in txt:
        return txt.split(',')
    else:
        # If no whitespace or commas, count odd-positioned lowercase letters
        return sum(1 for char in txt if char.islower() and (ord(char) - ord('a')) % 2 != 0)
