def split_words(txt):
    '''
    Given a string of words, return a dictionary with the count of words split on whitespace. 
    If no whitespace exists, return a single list containing the string reversed. 
    If neither condition is met, return a tuple of the total length of the string and the first character.

    Examples:
    split_words("Hello world!") ➞ {"count": 2}
    split_words("Hello,world!") ➞ ["!dlrow,olleH"]
    split_words("abcdef") ➞ (6, 'a')
    '''

    # Check for whitespace and count words
    if ' ' in txt:
        return {"count": len(txt.split())}  # Returning a dictionary instead of a list
    elif ',' in txt:
        return [txt[::-1]]  # Return reversed string as a list
    else:
        # Return a tuple with the string length and first character
        return (len(txt), txt[0])
