def split_words(txt):
    '''
    Given a string of words, return a list of words split on commas. 
    If no commas exist in the text, split on semicolons instead. 
    If no semicolons exist, return the number of capital letters with odd order in the alphabet as a JSON object. 
    Additionally, the function will sort the resulting words in reverse alphabetical order for better presentation.

    Examples:
    split_words("Hello world!") ➞ {"words": ["world!", "Hello"]}
    split_words("Hello;world!") ➞ {"words": ["Hello", "world!"]}
    split_words("ABCdef") ➞ {"count": 3} 
    '''

    txt = txt.lower()

    if ',' in txt:
        words = txt.split(',')
    elif ';' in txt:
        words = txt.split(';')
    else:
        capital_odd_count = sum(1 for char in txt if char.isupper() and (ord(char) - ord('A')) % 2 != 0)
        return {"count": capital_odd_count}  

    words.sort(reverse=True)
    return {"words": words}  
